class Solution:
    def kthSmallestPath(self, destination, k):
        row, col = destination[0], destination[1]
        dp = [[0] * (col + 1) for _ in range(row + 1)]
        for r in range(row + 1):
            for c in range(col + 1):
                if r == 0 or c == 0:
                    dp[r][c] = 1
                else:
                    dp[r][c] = dp[r - 1][c] + dp[r][c - 1]
        result = []
        r, c = row, col
        for _ in range(row + col):
            if c == 0:
                result.append('V')
                r -= 1
                continue
            if r == 0:
                result.append('H')
                c -= 1
                continue
            count_h = dp[r][c - 1]
            if k <= count_h:
                result.append('H')
                c -= 1
            else:
                k -= count_h
                result.append('V')
                r -= 1
        return ''.join(result)

