from math import comb

class Solution:
    def kthSmallestPath(self, destination, k):
        row, col = destination[0], destination[1]
        result = []
        for _ in range(row + col):
            if col == 0:
                result.append('V')
                row -= 1
                continue
            if row == 0:
                result.append('H')
                col -= 1
                continue
            count_h = comb(row + col - 1, col - 1)
            if k <= count_h:
                result.append('H')
                col -= 1
            else:
                k -= count_h
                result.append('V')
                row -= 1
        return ''.join(result)

