var kthSmallestPath = function(destination, k) {
    const row = destination[0], col = destination[1];
    const dp = [];
    for (let r = 0; r <= row; r++) dp.push(new Array(col + 1).fill(0));
    for (let r = 0; r <= row; r++) {
        for (let c = 0; c <= col; c++) {
            if (r === 0 || c === 0) {
                dp[r][c] = 1;
            } else {
                dp[r][c] = dp[r - 1][c] + dp[r][c - 1];
            }
        }
    }
    let r = row, c = col;
    const result = [];
    for (let step = 0; step < row + col; step++) {
        if (c === 0) {
            result.push('V'); r -= 1; continue;
        }
        if (r === 0) {
            result.push('H'); c -= 1; continue;
        }
        const countH = dp[r][c - 1];
        if (k <= countH) {
            result.push('H'); c -= 1;
        } else {
            k -= countH; result.push('V'); r -= 1;
        }
    }
    return result.join('');
};
